const d = $input.first().json;
const ctx = d.context;
const prompt = `Ты — юридический ассистент по трудовому праву. Твоя задача — кратко и точно сформулировать нарушение трудовых обязанностей со ссылками на нормативные акты.

## Данные о нарушении
Сотрудник: ${ctx.employee?.name || '[не указано]'}
Должность: ${ctx.employee?.position || '[не указано]'}
Подразделение: ${ctx.employee?.department || '[не указано]'}
Дата нарушения: ${ctx.violation?.date || '[не указано]'}
Описание: ${ctx.violation?.description || 'Прогул — отсутствие на рабочем месте без уважительной причины'}
Уважительная причина: ${ctx.respectableReason ? 'Есть: ' + ctx.respectableReasonComment : 'Отсутствует'}

## Чеклист (внутренняя инструкция)
${d.checklist_content}

## Задача
Сформулируй нарушение в 2-4 предложениях для включения в служебную записку. Укажи конкретные статьи, пункты. Формат: юридически грамотно, сухо, без лишних слов.
Отвечай ТОЛЬКО формулировкой нарушения, без вводных фраз.`;
return [{ json: { ...d, prompt_rag: prompt } }];

const inp = $input.first().json;
